<template>
    <index-page>
        <template v-slot:search-field>
            <date-picker id="date4" field="search_data.from_date" name="start_date" v-model="search_data.from_date"
                title="From Date" placeholder="dd/mm/yyyy" col="4" label="From Date" :tooltip="false"></date-picker>
            <date-picker id="date5" field="search_data.to_date" name="end_date" v-model="search_data.to_date"
                title="To Date" placeholder="dd/mm/yyyy" col="4" label="To Date" :disableToDates="search_data.from_date"
                :disableFutureDates="true"></date-picker>
            <v-select-container title="Select Category" field="search_data.category_id" col="col-md-5 col-lg-4">
                <v-select v-if="extraData.categories.length > 0" v-model="search_data.category_id" label="title"
                    :reduce="(obj) => obj.id" :options="extraData.categories" placeholder="--Select Category--"
                    :closeOnSelect="true"></v-select>
            </v-select-container>
        </template>
    </index-page>
</template>

<script>
const model = "events";

// Define table columns...
const tableColumns = [
    {
        field: "image_three",
        zoom_field: "image_one",
        title: "Image",
        image: true,
        imgWidth: "30px",
        align: "center",
        enable_data_sorting: false,
    },
    { field: "title", title: "Title" },
    { field: "category", title: "Category", subfield: "category.title" },
    { field: "venue", title: "Venue" },
    { field: "start_date", title: "Start_date" },
    { field: "end_date", title: "End_date" },
    {
        field: "sorting",
        title: "Sorting",
        sorting: true,
        namespace: "Events",
        auto: "",
        align: "center",
    },
    { field: "status", title: "Status", align: "center" },
    { field: "created_at", title: "Created at", date: true },
];

// Define excel column...
const json_fields = {
    Title: "title",
    Image: "image",
    Venue: "venue",
    "Start date": "start_date",
    "End date": "end_date",
    Sorting: "sorting",
    Status: "status",
    Description: "description",
};

export default {
    data() {
        return {
            page_title: "Event List",
            disablePastDates: false,
            disableToDate: 14,
            extraData: {
                categories: [],
            },
            model: model,
            json_fields: json_fields,
            fields_name: { default: "Select One", title: "Title", venue: "Venue" },
            search_data: {
                pagination: this.$route.query.pagination ?? 10,
                field_name: this.$route.query.field_name ?? "",
                value: this.$route.query.value ?? "",
                status: this.$route.query.status ?? "",
                from_date: this.$route.query.from_date ?? "",
                to_date: this.$route.query.to_date ?? "",
            },
            table: {
                columns: tableColumns,
                routes: {},
                datas: [],
                meta: [],
                links: [],
            },
        };
    },
    provide() {
        return {
            model: this.model,
            fields_name: this.fields_name,
            search_data: this.search_data,
            table: this.table,
            json_fields: this.json_fields,
            validate: this.validation,
            search: this.search,
            resetSearchData: this.resetSearchData,
        };
    },
    methods: {
        search() {
            this.$router.push({ name: this.model + '.index', query: { ...this.search_data } });
            this.get_paginate(this.model, this.search_data);
        },
        resetSearchData() {
            this.search_data.pagination = 10;
            this.search_data.category_id = '';
            this.search_data.field_name = "";
            this.search_data.value = "";
            this.search_data.status = "";
            this.search_data.to_date = "";
            this.search_data.from_date = "";
        },
    },

    created() {
        this.getRouteName(this.model);
        this.setBreadcrumbs(this.model, "index");
        this.search();
        this.get_paginate(
            "category",
            { allData: true, module_name: "events" },
            "categories"
        );
    },
    validators: {
        "search_data.category_id": function (value = null) {
            return Validator.value(value);
        },

        "search_data.from_date": function (value = null) {
            return Validator.value(value);
        },
        "search_data.to_date": function (value = null) {
            const that = this;
            return Validator.value(value).custom(function () {
                if (!Validator.isEmpty(value) && that.search_data.to_date) {
                    const end = new Date(value);
                    const start = new Date(that.search_data.from_date);

                    if (start > end) {
                        return "End date must higher";
                    }
                }
            });
        },
    },
};
</script>
